def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build entity relationships to create connected sentences
    entity_info = {}
    all_subjects = set()
    all_objects = set()

    for triple in triples:
        subj = triple.subject
        pred = triple.predicate.lower()
        obj = triple.object

        all_subjects.add(subj)
        all_objects.add(obj)

        if subj not in entity_info:
            entity_info[subj] = []
        entity_info[subj].append((pred, obj))

    # Find main subject (athlete or most connected entity)
    main_subject = max(entity_info.keys(), key=lambda s: len(entity_info[s]))

    # Group triples by subject and predicate for proper handling
    from collections import defaultdict
    predicate_groups = defaultdict(list)
    for subj, pred, obj in [(t.subject, t.predicate.lower(), t.object) for t in triples]:
        predicate_groups[(subj, pred)].append(obj)

    # Build a chain of connected clauses using entity linking
    processed_triples = set()

    def get_clause_text(pred, obj):
        """Convert a triple to natural language text"""
        if pred == "birthDate":
            return f"was born on {obj}"
        elif pred == "birthYear":
            return f"was born in {obj}"
        elif pred == "birthPlace":
            return f"was born in {obj}"
        elif pred == "height":
            return f"measures {obj} in height"
        elif pred == "weight":
            return f"weighs {obj}"
        elif pred == "league":
            return f"plays in {obj}"
        elif pred == "club":
            return f"plays for {obj}"
        elif pred == "currentclub":
            return f"currently plays for {obj}"
        elif pred == "currentteam":
            return f"currently plays for {obj}"
        elif pred == "formerTeam":
            return f"previously played for {obj}"
        elif pred == "position":
            return f"plays as a {obj}"
        elif pred == "manager":
            return f"is managed by {obj}"
        elif pred == "coach":
            return f"is coached by {obj}"
        elif pred == "owner":
            return f"is owned by {obj}"
        elif pred == "city":
            return f"is based in {obj}"
        elif pred == "country":
            return f"comes from {obj}"
        elif pred == "isPartOf":
            return f"part of {obj}"
        elif pred == "season":
            return f"season is {obj}"
        elif pred == "foundingDate":
            return f"founded on {obj}"
        elif pred == "utcOffset":
            return f"UTC offset is {obj}"
        elif pred == "timeZone":
            return f"time zone is {obj}"
        elif pred == "areaTotal":
            return f"area is {obj}"
        elif pred == "demonym":
            return f"residents are called {obj}"
        elif pred == "language":
            return f"the official language is {obj}"
        elif pred == "officialLanguage":
            return f"the official language is {obj}"
        elif pred == "anthem":
            return f"the national anthem is {obj}"
        elif pred == "leader":
            return f"the leader is {obj}"
        elif pred == "leaderTitle":
            return f"the leader title is {obj}"
        elif pred == "mostChampions":
            return f"the team with the most championships is {obj}"
        elif pred == "currency":
            return f"the currency is {obj}"
        elif pred == "draftTeam":
            return f"drafted by {obj}"
        elif pred == "draftPick":
            return f"draft pick is {obj}"
        elif pred == "draftRound":
            return f"draft round is {obj}"
        elif pred == "draftYear":
            return f"draft year is {obj}"
        elif pred == "playerNumber":
            return f"player number is {obj}"
        elif pred == "college":
            return f"college is {obj}"
        elif pred == "debutTeam":
            return f"debuted with {obj}"
        elif pred == "activeYearsStartYear":
            return f"active since {obj}"
        elif pred == "universityTeam":
            return f"university team is {obj}"
        elif pred == "stadium":
            return f"stadium is {obj}"
        elif pred == "generalManager":
            return f"general manager is {obj}"
        elif pred == "chairman":
            return f"chairman is {obj}"
        elif pred == "deathPlace":
            return f"death place is {obj}"
        elif pred == "ethnicGroup":
            return f"has ethnic group {obj}"
        else:
            return f"{pred}: {obj}"

    # Process main subject's triples first, handling multiple objects for same predicate
    main_clauses = []
    seen_predicates = set()

    for pred, obj in entity_info.get(main_subject, []):
        if (main_subject, pred) in seen_predicates:
            # This predicate already processed, skip (we'll handle multiple values together)
            continue
        seen_predicates.add((main_subject, pred))

        # Get all objects for this predicate
        all_objects_for_pred = predicate_groups.get((main_subject, pred), [obj])

        if len(all_objects_for_pred) == 1:
            clause = get_clause_text(pred, all_objects_for_pred[0])
        else:
            # Multiple objects for same predicate (e.g., multiple clubs)
            objects_str = ", ".join(all_objects_for_pred[:-1]) + " and " + all_objects_for_pred[-1] if len(all_objects_for_pred) > 1 else all_objects_for_pred[0]
            clause = get_clause_text_multiple(pred, objects_str)

        main_clauses.append(clause)
        processed_triples.add((main_subject, pred, obj))

    def get_clause_text_multiple(pred, objects_str):
        """Handle multiple objects for same predicate"""
        if pred == "club":
            return f"plays for {objects_str}"
        elif pred == "currentclub":
            return f"currently plays for {objects_str}"
        elif pred == "currentteam":
            return f"currently plays for {objects_str}"
        elif pred == "formerTeam":
            return f"previously played for {objects_str}"
        elif pred == "birthPlace":
            return f"was born in {objects_str}"
        else:
            return f"{objects_str}"

    # Now find and connect related entities (when one object is another subject)
    connected_clauses = []
    for subj in entity_info.keys():
        if subj == main_subject:
            continue
        for pred, obj in entity_info[subj]:
            if (subj, pred, obj) not in processed_triples:
                clause = get_clause_text(pred, obj)
                # Remove the subject from the clause text for relative clause construction
                # The clause text already starts with a verb or descriptor
                connected_clauses.append(clause)
                processed_triples.add((subj, pred, obj))

    # Build the final sentence - ALL information in ONE complex sentence
    if main_clauses:
        # Start with main subject and first clause
        if len(main_clauses) == 1:
            base = f"{main_subject} {main_clauses[0]}"
        else:
            # Connect main clauses with commas and 'and'
            base = f"{main_subject} {main_clauses[0]}"
            for clause in main_clauses[1:-1]:
                base += f", {clause}"
            if len(main_clauses) > 1:
                base += f", and {main_clauses[-1]}"

        # Append connected clauses using relative clauses
        if connected_clauses:
            for i, clause in enumerate(connected_clauses):
                if i == 0:
                    base += f", which {clause.lower()}"
                else:
                    base += f", and {clause.lower()}"

        sentence = base + "."
    else:
        # Handle case where main subject has no clauses but we have triples
        all_clauses = []
        for triple in triples:
            clause = get_clause_text(triple.predicate.lower(), triple.object)
            all_clauses.append(f"{triple.subject} {clause}")

        if len(all_clauses) == 1:
            sentence = all_clauses[0] + "."
        else:
            # Join multiple subjects with appropriate conjunctions
            sentence = all_clauses[0] + " and " + all_clauses[1] + "."
            for clause in all_clauses[2:]:
                sentence = sentence.rstrip(".") + ", " + clause

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

